output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?house ?successionLabel WHERE {
  ?monarch wdt:P39 wd:Q14778 .
  ?monarch wdt:P1344 ?house .
  ?monarch wdt:P1000 ?start .
  ?monarch wdt:P2337 ?succession .
  ?succession rdfs:label ?successionLabel .
  FILTER(lang(?successionLabel) = 'en')
  {
    SELECT ?house(MIN(?start) AS ?minStart) WHERE {
      ?monarch2 wdt:P39 wd:Q14778 .
      ?monarch2 wdt:P1344 ?house .
      ?monarch2 wdt:P1000 ?start .
    }
    GROUP BY ?house
  }
  FILTER(?start = ?minStart)
}
